  `sub_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'е≠РйҐШеПЈпЉИе¶ВпЉЪ(1), (2) жИЦ 1.1, 1.2пЉЙ',
  `content_html` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'HTMLж†ЉеЉПзЪДе∞ПйҐШеЖЕеЃє',
  `content_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'зЇѓжЦЗжЬђеЖЕеЃє',
  `score` int(0) NULL DEFAULT 0 COMMENT 'еИЖеАЉ',
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'жЬ™еИЖз±ї' COMMENT 'еИЖз±їпЉИе¶ВпЉЪжХ∞е≠¶гАБиѓ≠жЦЗгАБиЛ±иѓ≠з≠ЙпЉЙ',
  `tags` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'ж†Зз≠ЊпЉИйАЧеПЈеИЖйЪФпЉЙ',
  `difficulty` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'дЄ≠з≠Й' COMMENT 'йЪЊеЇ¶пЉЪзЃАеНХгАБдЄ≠з≠ЙгАБеЫ∞йЪЊ',
