  `full_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'еЃМжХіеЖЕеЃєпЉИеМЕеРЂйҐШеПЈпЉЙ',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'е§Зж≥®дњ°жБѓ',
  `created_at` timestamp(0) NULL DEFAULT CURRENT_TIMESTAMP,
